mapper.insert:
insert into store_dish (store_id, dish_id, status, stock, warning_stock, create_user, update_user, create_time, update_time) select #{storeId}, d.id, ifnull(d.status, 1), #{defaultStock}, #{defaultWarningStock}, 0, 0, now(), now() from dish d where d.id in
#{dishId}
and ((d.dish_scope = 1 or (d.dish_scope is null and d.store_id is null)) or ((d.dish_scope = 2 or (d.dish_scope is null and d.store_id is not null)) and d.store_id = #{storeId})) on duplicate key update update_time = now(), update_user = 0

mapper.update:
update store_dish
set stock = stock - #{deductNum}, update_time = now(), update_user = 0
where store_id = #{storeId}
  and dish_id = #{dishId}
  and status = 1
  and stock >= #{deductNum}

update store_dish
set stock = stock + #{rollbackNum}, update_time = now(), update_user = 0
where store_id = #{storeId}
  and dish_id = #{dishId}

update store_dish
set stock = #{stock},
    update_time = now(),
    update_user = 0
where store_id = #{storeId}
  and dish_id = #{dishId}

update store_dish
set warning_stock = #{warningStock},
    update_time = now(),
    update_user = 0
where store_id = #{storeId}
  and dish_id = #{dishId}
